<template>
  <div class="settings">
    <v-col cols="12">
      <h1>Settings</h1>
      <v-divider></v-divider>
      <v-switch v-model="isDark" :label="isDarkThemeLabel"></v-switch>
      <v-switch v-model="isMiniNav" :label="isMiniNavLabel"></v-switch>
      <v-switch
        v-model="isExpandOnHover"
        :label="isExpandOnHoverLabel"
        color="secondary"
      >
      </v-switch>
    </v-col>
  </div>
</template>

<script>
export default {
  computed: {
    isDarkThemeLabel() {
      return this.isDark ? "Dark" : "Light";
    },
    isMiniNavLabel() {
      return this.isMiniNav ? "Mini" : "Full";
    },
    isExpandOnHoverLabel() {
      return this.isExpandOnHover ? "Expand" : "Not Expand";
    },
    isDark: {
      get() {
        return this.$store.state.isDark;
      },
      set(value) {
        this.$store.commit("updateIsDark", value);
      },
    },
    isMiniNav: {
      get() {
        return this.$store.state.isMiniNav;
      },
      set(value) {
        this.$store.commit("updateIsMiniNav", value);
      },
    },
    isExpandOnHover: {
      get() {
        return this.$store.state.isExpandOnHover;
      },
      set(value) {
        this.$store.commit("updateIsExpandOnHover", value);
      },
    },
  },
};
</script>

